import React, { useEffect, useState } from 'react'
import Navbaar from './navbaar/nav'
import Main from './main/Main'
import io from 'socket.io-client'
import axios from 'axios'
import Print from './printPage/Print' 
import { Route, Routes, useNavigate } from 'react-router'

const App = () => {

   const navigate = useNavigate();

  const [myid,setId] = useState(null);
  const [FileUrl,setFileUrl] = useState('');

  const postData = async (data)=>{

    await axios.post("http://localhost:4000/sendData",{
          user_id:data
    })
  } 

  useEffect(()=>{

    const socket = io('http://localhost:4000');

     socket.on("justForMe",(data)=>{
       postData(data)
       setId(data)  
    })

    socket.on("sendData",(fileUrl)=>{ 
        setFileUrl(fileUrl)
    })
    // setFileUrl("Hello")
  },[FileUrl])


      if(FileUrl === ''){

      return (
         <main>

          <Navbaar/>

          <Routes>
               <Route path='/' element={<Main imageUrl={myid}/>}/>
               <Route path='/print' element={<Print/>}/>
              
           </Routes>

        </main>
  )
  }
  else{
    setFileUrl('')
    navigate('/print');
  }
  
}

export default App
